pub fn ensure_jq_worker_available() -> Result<std::path::PathBuf, String> {
    match resolve_jq_worker_bin(None) {
        Some(bin) if bin.exists() => { ... pool.warm(); Ok(bin) }
        Some(bin) => Err(format!("ritual-jq-worker binary not found at resolved path: {}", bin.display())),
        None => Err(format!("ritual-jq-worker binary not found. Set RITUAL_JQ_WORKER_BIN ...")),
    }
}
